final:
module top_module(
    input clk,
    input async_in,
    input reset,
    output reg sync_out
    );reg unused_meta;

always @(posedge clk) 
    if (reset)
       begin
        unused_meta <= 1'b0;
        sync_out <= 1'b0;
       end
    else
       begin
        unused_meta <= async_in;
        sync_out <= unused_meta;
       end


endmodule
